class SecureHttpClient {
  final http.Client _client = http.Client();
  final SecureProductionLogger _logger = SecureProductionLogger();

  Future<http.Response> get(Uri uri, {Map<String, String>? headers}) async {
    _logger.logHTTPRequest('GET', uri.toString(), headers, null);
    
    try {
      final response = await _client.get(uri, headers: headers);
      _logger.logHTTPResponse(response.statusCode, response.body, response.headers);
      return response;
    } catch (e, stackTrace) {
      _logger.logError('HTTP GET failed', e, stackTrace);
      rethrow;
    }
  }

  Future<http.Response> post(Uri uri, {Map<String, String>? headers, dynamic body}) async {
    _logger.logHTTPRequest('POST', uri.toString(), headers, body);
    
    try {
      final response = await _client.post(uri, headers: headers, body: body);
      _logger.logHTTPResponse(response.statusCode, response.body, response.headers);
      return response;
    } catch (e, stackTrace) {
      _logger.logError('HTTP POST failed', e, stackTrace);
      rethrow;
    }
  }

  void close() {
    _client.close();
  }
}

